VALUES
  ('generalpolice-94737317-moex-00322', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '熱機是將熱能轉換為機械能的動力裝置，可為發電機及機動車提供動力。卡諾熱機在氣缸裝理想氣體，藉 由兩個可逆等溫過程及兩個可逆絕熱過程，利用氣體的熱脹冷縮，以推動機械循環工作。在卡諾循環的過 程，下列何者正確？', '["在等溫膨脹過程，理想氣體的內能變化為負值", "在等溫壓縮過程，理想氣體的內能變化為正值", "理想卡諾熱機為可逆循環過程，熵的變化為零", "熱機可將高溫熱庫的溫度提高，以提昇機械效率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00323', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '已知絕對溫度為 T 的物體散發熱輻射的功率 P = A·σ·ε·T4，其中 A 為該物體的表面積、 常數σ = 5.67×10-8J/(s·m2·K4)、ε為輻射率。若在火災現場有表面積約為10m2的物體燃燒，高溫達1000K， 在假設ε 1的條件下，該燃燒物體的熱輻射功率為1000W熱吹風機的幾倍？', '["567000", "56700", "5670", "567 ≈"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00324', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', 'U形管兩臂中裝有等高的水銀，若在其右臂注入13.6cm高的水時，則左臂的水銀面從原來液面上升多少cm？ （水銀密度為13.6g/cm3）', '["2.0", "1.0", "0.50", "13.6"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00325', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '一密度為820kg/m3的木塊，放置於密度為1025kg/m3的海水，則木塊沒入海水中的體積與其總體積的比 約為多少？', '["0.20", "0.25", "0.50", "0.80"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00326', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '甲與乙分別住在同一棟公寓的1樓與3樓，該公寓的水塔置於樓頂上，水塔內的水位離地面15 m，甲與 乙家中的水源直接來自水塔，水龍頭位置分別為離地面高度1m及7m。假設水龍頭的截面積遠小於水塔 截面積，則甲、乙打開水龍頭所見的水流速率比值V /V 約為多少？ 甲 乙', '["7", "3.06", "1.75", "1.32"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00327', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '一台水壓機，其大小活塞面積分別為100cm2與40cm2，如圖所示。如果兩個活塞的上方沒有額外負重， 兩個活塞底部同高時恰好平衡，若在小活塞上方放上一個 1.0 kg 重的物體，則兩個活塞底部高度差為多 少公分會達到平衡？', '["1.0", "5.0", "10", "25"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
