  ('generalpolice-94737317-moex-00330', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '下列C、N、O、F四種元素的電負度序列，何者正確？', '["C<N<O<F", "F<O<N<C", "N<C<O<F", "F<O<C<N"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00331', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '有關鹼金屬的敘述，下列何者錯誤？', '["化性活潑，在自然界都以化合態存在", "易與水作用產生氫氧化物和氫氣", "游離能隨原子序增加而增大", "價電子數為1，通常形成+1氧化態的化合物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
